/* global wp, ajaxurl, WCMelhorEnvioOrdersParams */
jQuery(function ($) {

    /**
     * Admin class.
     *
     * @type {Object}
     */
    var WCMelhorEnvioOrders = {

        /**
         * Initialize actions.
         */
        init: function () {
            $(document.body)
                .on('click', '.me_add_to_cart, .me_buy_shipping, .me_print_label', this.RequestLabel)
                .on('click', '.delete-melhor-envio-data', this.DeleteMeta)

                // dokan integration
                .on('click', '.dokan-order-action [href*="admin-ajax.php?action=melhor_envio_add_to_cart"], .dokan-order-action [href*="melhorenvio.com.br"]', this.RequestLabel)
        },

        /**
         * Block.
         */
        block: function (el) {
            $(el).block({
                message: null,
                overlayCSS: {
                    background: '#fff',
                    opacity: 0.6
                }
            });
        },

        /**
         * Unblock.
         */
        unblock: function (el) {
            $(el).unblock();
        },

        /**
         * Request Melhor Envio Label.
         *
         * @param {Object} evt Current event.
         */
        RequestLabel: function (evt) {
            evt.preventDefault();

            var el = $(this);

            if (el.hasClass('me-is-single')) {
                var wrapper = el.closest('.inside');
            } else {
                var wrapper = el
            }

            const is_single = wrapper !== el

            if (el.attr('href').indexOf('melhorenvio.com.br') >= 0 || el.hasClass('me_print_label')) {
                window.open(el.attr('href'), '_blank');
                return;
            }

            var self = WCMelhorEnvioOrders;
            self.block('#posts-filter, #order-filter, #wc_melhor_envio_admin .inside');

            let data = {
                is_single: is_single,
                nfe: $('#order-invoice-id').val(),
                service: $('#order-service-id').val(),
                reverse: $('#melhor-envio-is-reverse').is(':checked'),
            }

            // Adiciona campos personalizados ao objeto data
            $('.me-custom-field').each(function () {
                var fieldName = $(this).attr('name');
                var fieldValue;

                if ($(this).is(':checkbox')) {
                    // Para checkboxes, pega apenas os que estão marcados
                    if ($(this).is(':checked')) {
                        fieldValue = $(this).val();
                    } else {
                        return; // Ignora os checkboxes desmarcados
                    }
                } else {
                    // Para outros tipos de campos, pega o valor diretamente
                    fieldValue = $(this).val();
                }

                // Verifica se já existe um array para esse nome no objeto data
                if (!data[fieldName]) {
                    data[fieldName] = [];
                }

                // Adiciona o valor ao array correspondente
                data[fieldName].push(fieldValue);
            });

            // Add tracking code.
            $.ajax({
                type: 'POST',
                url: el.attr('href'),
                data: data,
                success: function (response) {
                    console.log(response);

                    if (false === response.success) {
                        alert('Erro: ' + response.data)
                    } else {
                        wrapper.replaceWith(response.data);
                    }
                },
                error: function (error) {
                    alert('Ocorreu um erro interno. Tente novamente');
                    console.log('Ocorreu um erro', error)
                },
                complete: function () {
                    self.unblock('#posts-filter, #order-filter, #wc_melhor_envio_admin .inside');
                }
            });
        },

        /**
         * Delete Melhor Envio Label.
         *
         * @param {Object} evt Current event.
         */
        DeleteMeta: function (evt) {
            evt.preventDefault();
            const el = $(this);

            if (!window.confirm('Ainda será necessário cancelar a etiqueta no Melhor Envio e o ID atual não estará mais associado a este pedido. Continuar?')) {
                return;
            }

            var self = WCMelhorEnvioOrders;
            self.block('#wc_melhor_envio_admin');

            // Add tracking code.
            $.ajax({
                type: 'POST',
                url: el.attr('href'),
                data: {
                    order_id: el.data('order-id')
                },
                success: function (response) {
                    console.log(response);

                    if (false === response.success) {
                        alert('Erro: ' + response.data)
                    } else {
                        $('.me-metabox-content').replaceWith(response.data);
                    }
                },
                error: function (error) {
                    alert('Ocorreu um erro interno. Tente novamente');
                    console.log('Ocorreu um erro', error)
                },
                complete: function () {
                    self.unblock('#wc_melhor_envio_admin');
                }
            });
        },
    };

    WCMelhorEnvioOrders.init();
});
